exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <type_traits>

struct Wallet {
    double m_balance;
    explicit Wallet(double balance) : m_balance{balance} {}
};

static_assert(std::is_constructible_v<Wallet, double>,
    "Wallet must have a constructor that accepts a double");

Wallet add_funds(Wallet w, double amount) {
    return Wallet{w.m_balance + amount};
}

int main() {
    double initial{};
    double deposit{};
    std::cin >> initial >> deposit;

    Wallet w{initial};
    Wallet result = add_funds(w, deposit);

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Initial: " << w.m_balance << "\n";
    std::cout << "After deposit: " << result.m_balance << "\n";

    return 0;
}

