exercises.solution_code:
#include <iostream>
#include <iomanip>
#include <type_traits>

class Rectangle {
public:
    double m_width;
    double m_height;

    Rectangle(double width, double height) : m_width{width}, m_height{height} {}

    explicit Rectangle(double side) : m_width{side}, m_height{side} {}

    double area() const { return m_width * m_height; }
};

static_assert(std::is_constructible_v<Rectangle, double, double>,
    "Rectangle must be constructible from two doubles");
static_assert(std::is_constructible_v<Rectangle, double>,
    "Rectangle must be constructible from one double");

Rectangle scale(Rectangle r, double factor) {
    return Rectangle{r.m_width * factor, r.m_height * factor};
}

int main() {
    double w{}, h{}, s{}, f{};
    std::cin >> w >> h >> s >> f;

    Rectangle rect{w, h};
    Rectangle sq{s};
    Rectangle scaled = scale(sq, f);

    std::cout << std::fixed << std::setprecision(2);
    std::cout << "Rectangle area: " << rect.area() << "\n";
    std::cout << "Square area: " << sq.area() << "\n";
    std::cout << "Scaled square area: " << scaled.area() << "\n";

    return 0;
}
